import { getApi } from "@/shared/api/api";
import { API_ROUTES } from "@/shared/config/api-routes";
import type {
  ChangeTempPasswordRequest,
  ConfirmForgotPasswordRequest,
  ConfirmForgotPasswordResponse,
  ForgotPasswordRequest,
  ForgotPasswordResponse,
  OAuthAppleRequest,
  OAuthGoogleRequest,
  OtpEntity,
  RefreshTokenRequest,
  RefreshTokenResponse,
  SendOtpRequest,
  SendOtpResponse,
  SignInRequest,
  SignInResponse,
  SignOutRequest,
  SignUpRequest,
  VerifyOtpRequest,
} from "@/shared/types/auth.types";

import {
  CONFIRM_FORGOT_PASSWORD_RESPONSE_SCHEMA,
  FORGOT_PASSWORD_RESPONSE_SCHEMA,
  OTP_ENTITY_SCHEMA,
  REFRESH_TOKEN_RESPONSE_SCHEMA,
  SEND_OTP_RESPONSE_SCHEMA,
  SIGN_IN_RESPONSE_SCHEMA,
} from "./dto/auth.dto";

export async function signUp(data: SignUpRequest): Promise<SignInResponse> {
  const api = await getApi();
  const response = await api.post(API_ROUTES.AUTH.SIGN_UP, data);

  return SIGN_IN_RESPONSE_SCHEMA.parse(response.data);
}

export async function sendOtp(data: SendOtpRequest): Promise<SendOtpResponse> {
  const api = await getApi();
  const response = await api.post(API_ROUTES.AUTH.SEND_OTP, data);

  return SEND_OTP_RESPONSE_SCHEMA.parse(response.data);
}

export async function verifyOtp(data: VerifyOtpRequest): Promise<OtpEntity> {
  const api = await getApi();
  const response = await api.post(API_ROUTES.AUTH.VERIFY_OTP, data);

  return OTP_ENTITY_SCHEMA.parse(response.data);
}

export async function signIn(data: SignInRequest): Promise<SignInResponse> {
  const api = await getApi();
  const response = await api.post(API_ROUTES.AUTH.SIGN_IN, data);

  return SIGN_IN_RESPONSE_SCHEMA.parse(response.data);
}

export async function changeTempPassword(
  data: ChangeTempPasswordRequest,
): Promise<SignInResponse> {
  const api = await getApi();
  const response = await api.post(API_ROUTES.AUTH.CHANGE_TEMP_PASSWORD, data);

  return SIGN_IN_RESPONSE_SCHEMA.parse(response.data);
}

export async function refreshToken(
  data: RefreshTokenRequest,
): Promise<RefreshTokenResponse> {
  const api = await getApi();
  const response = await api.post(API_ROUTES.AUTH.REFRESH_TOKEN, data);

  return REFRESH_TOKEN_RESPONSE_SCHEMA.parse(response.data);
}

export async function signOut(data: SignOutRequest): Promise<void> {
  const api = await getApi({ auth: true });
  await api.post(API_ROUTES.AUTH.SIGN_OUT, data);
}

export async function forgotPassword(
  data: ForgotPasswordRequest,
): Promise<ForgotPasswordResponse> {
  const api = await getApi();
  const response = await api.post(API_ROUTES.AUTH.FORGOT_PASSWORD, data);

  return FORGOT_PASSWORD_RESPONSE_SCHEMA.parse(response.data);
}

export async function confirmForgotPassword(
  data: ConfirmForgotPasswordRequest,
): Promise<ConfirmForgotPasswordResponse> {
  const api = await getApi();
  const response = await api.post(
    API_ROUTES.AUTH.CONFIRM_FORGOT_PASSWORD,
    data,
  );

  return CONFIRM_FORGOT_PASSWORD_RESPONSE_SCHEMA.parse(response.data);
}

export async function checkEmailExists(
  email: string,
): Promise<{ exists: boolean }> {
  const api = await getApi();
  const response = await api.post(API_ROUTES.AUTH.EMAIL_EXISTS, { email });

  return response.data;
}

export async function checkPhoneExists(
  phone: string,
): Promise<{ exists: boolean }> {
  const api = await getApi();
  const response = await api.post(API_ROUTES.AUTH.PHONE_EXISTS, { phone });

  return response.data;
}

export async function oauthGoogle(
  data: OAuthGoogleRequest,
): Promise<SignInResponse> {
  const api = await getApi();
  const response = await api.post(API_ROUTES.AUTH.OAUTH_GOOGLE, data);

  return SIGN_IN_RESPONSE_SCHEMA.parse(response.data);
}

export async function oauthApple(
  data: OAuthAppleRequest,
): Promise<SignInResponse> {
  const api = await getApi();
  const response = await api.post(API_ROUTES.AUTH.OAUTH_APPLE, data);

  return SIGN_IN_RESPONSE_SCHEMA.parse(response.data);
}

export const API_ROUTES = {
  AUTH: {
    SIGN_UP: "/auth/sign-up",
    SEND_OTP: "/auth/send-otp",
