1	"use client";
2	
3	import { zodResolver } from "@hookform/resolvers/zod";
4	import { signIn } from "next-auth/react";
5	import Link from "next/link";
6	import Script from "next/script";
7	import { useEffect, useRef, useState } from "react";
8	import { useForm } from "react-hook-form";
9	import { z } from "zod";
10	
11	import Image from "next/image";
12	
13	import { APP_ROUTES } from "@/shared/config/app-routes";
14	import { hardPush } from "@/shared/lib/routing/hard-push";
15	import { getIsClient } from "@/shared/lib/utils/get-is-client";
16	import { Form } from "@/shared/ui/form/form";
17	import { FormControl } from "@/shared/ui/form/form-control";
18	import { FormField } from "@/shared/ui/form/form-field";
19	import { FormItem } from "@/shared/ui/form/form-item";
20	import { FormLabel } from "@/shared/ui/form/form-label";
21	import { FormMessage } from "@/shared/ui/form/form-message";
22	import { Input } from "@/shared/ui/input";
23	import { toast } from "@/shared/ui/notification";
24	import { PasswordInput } from "@/shared/ui/password-input";
25	
26	const loginSchema = z.object({
27	  email: z.string().email("Please enter a valid email"),
28	  password: z.string().min(1, "Password is required"),
29	});
30	
31	type LoginFormData = z.infer<typeof loginSchema>;
32	
33	type GoogleAccountsId = {
34	  initialize: (config: {
35	    client_id: string | undefined;
36	    callback: (response: { credential: string }) => void;
37	  }) => void;
38	  renderButton: (
39	    container: HTMLElement,
40	    options: { type: string; theme: string; size: string; width: number },
41	  ) => void;
42	};
43	
44	declare global {
45	  interface Window {
46	    google?: { accounts?: { id?: GoogleAccountsId } };
47	  }
48	}
49	
50	function GoogleIcon() {
51	  return (
52	    <svg
53	      aria-hidden="true"
54	      width="20"
55	      height="20"
56	      viewBox="0 0 20 20"
57	      fill="none"
58	      xmlns="http://www.w3.org/2000/svg"
59	    >
60	      <path
61	        d="M19.6 10.23c0-.68-.06-1.36-.18-2H10v3.79h5.37a4.61 4.61 0 0 1-1.99 3.01v2.5h3.22c1.88-1.73 2.96-4.28 2.96-7.3z"
62	        fill="#4285F4"
63	      />
64	      <path
65	        d="M10 20c2.7 0 4.96-.9 6.61-2.43l-3.22-2.5c-.9.6-2.04.96-3.39.96-2.61 0-4.82-1.76-5.61-4.13H1.06v2.57A9.99 9.99 0 0 0 10 20z"
66	        fill="#34A853"
67	      />
68	      <path
69	        d="M4.39 11.9A5.9 5.9 0 0 1 4.08 10c0-.66.12-1.3.31-1.9V5.53H1.06A9.99 9.99 0 0 0 0 10c0 1.61.38 3.13 1.06 4.47l3.33-2.57z"
70	        fill="#FBBC05"
71	      />
72	      <path
73	        d="M10 3.97c1.47 0 2.8.51 3.84 1.5l2.87-2.87C15 .9 12.71 0 10 0A9.99 9.99 0 0 0 1.06 5.53L4.39 8.1C5.18 5.73 7.39 3.97 10 3.97z"
74	        fill="#EA4335"
75	      />
76	    </svg>
77	  );
78	}
79	
80	function AppleIcon() {
81	  return (
82	    <Image
83	      src="/new-design-images/auth/apple-logo.svg"
84	      alt="apple"
85	      width={17}
86	      height={20}
87	      className="shrink-0"
88	    />
89	  );
90	}
91	
92	function UaePassIcon() {
93	  return (
94	    <Image
95	      src="/new-design-images/auth/uae-pass-logo.svg"
96	      alt="uae-pass"
97	      width={21}
98	      height={20}
99	      className="shrink-0"
100	    />
101	  );
102	}
103	
104	export default function SignInPage() {
105	  const [isLoading, setIsLoading] = useState(false);
106	  const [googleLoading, setGoogleLoading] = useState(false);
107	  const [callbackUrl, setCallbackUrl] = useState<string | null>(null);
108	  const googleBtnRef = useRef<HTMLDivElement>(null);
109	  const googleInitialized = useRef(false);
110	
111	  useEffect(() => {
112	    if (!getIsClient()) return;
113	    const params = new URLSearchParams(window.location.search);
114	    setCallbackUrl(params.get("callbackUrl"));
115	  }, []);
116	
117	  const handleGoogleCredential = async (response: { credential: string }) => {
118	    setGoogleLoading(true);
119	    try {
120	      const result = await signIn("google-oauth", {
121	        idToken: response.credential,
122	        redirect: false,
123	      });
124	
125	      if (result?.ok) {
126	        const params = new URLSearchParams(window.location.search);
127	        hardPush(params.get("callbackUrl") || APP_ROUTES.APP.MY_DEALS);
128	      } else {
129	        toast.error("Google Sign In Failed", {
130	          description: "Please try again",
131	        });
132	        setGoogleLoading(false);
133	      }
134	    } catch {
135	      toast.error("Google Sign In Failed", {
136	        description: "An unexpected error occurred",
137	      });
138	      setGoogleLoading(false);
139	    }
140	  };
141	
142	  const initGoogleButton = () => {
143	    const google = window.google;
144	    if (!google?.accounts?.id || !googleBtnRef.current || googleInitialized.current) return;
145	
146	    googleInitialized.current = true;
147	
148	    google.accounts.id.initialize({
149	      client_id: process.env.NEXT_PUBLIC_GOOGLE_CLIENT_ID,
150	      callback: handleGoogleCredential,
151	    });
152	
153	    google.accounts.id.renderButton(googleBtnRef.current, {
154	      type: "standard",
155	      theme: "outline",
156	      size: "large",
157	      width: googleBtnRef.current.offsetWidth || 200,
158	    });
159	  };
160	
161	  const form = useForm<LoginFormData>({
162	    resolver: zodResolver(loginSchema),
163	    defaultValues: { email: "", password: "" },
164	  });
165	
166	  const onSubmit = async (data: LoginFormData) => {
167	    setIsLoading(true);
168	    try {
169	      const result = await signIn("credentials", {
170	        email: data.email,
171	        password: data.password,
172	        redirect: false,
173	      });
174	
175	      if (result?.error) {
176	        toast.error("Sign In Failed", {
177	          description: "Invalid email or password",
178	        });
179	        return;
180	      }
181	
182	      if (result?.ok) {
183	        hardPush(callbackUrl || APP_ROUTES.APP.MY_DEALS);
184	      }
185	    } catch {
186	      toast.error("Sign In Failed", {
187	        description: "An unexpected error occurred",
188	      });
189	    } finally {
190	      setIsLoading(false);
191	    }
192	  };
193	
194	  return (
195	    <>
196	      <Script
197	        src="https://accounts.google.com/gsi/client"
198	        strategy="afterInteractive"
199	        onLoad={initGoogleButton}
200	      />
201	      <div className="flex w-full flex-col gap-5">
202	        {/* Header */}
203	        <div className="flex flex-col">
204	          <h1 className="font-light font-new-serif text-[#44403C] text-xl leading-[140%]">
205	            Welcome Back
206	          </h1>
207	          <p className="font-new-sans text-[#44403C] text-sm leading-[150%] tracking-[-0.01em]">
208	            Login to your account to access LuxFlow
209	          </p>
210	        </div>
211	
212	        {/* Social Buttons */}
213	        <div className="flex flex-col gap-2 sm:flex-row">
214	          {/* Google — overlay approach */}
215	          <div className="relative h-12 w-full sm:flex-1">
216	            <div className="pointer-events-none flex h-12 w-full items-center justify-center gap-2 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-4 py-3 font-medium font-new-sans text-[#44403C] text-sm tracking-[-0.01em]">
217	              <GoogleIcon />
218	              <span className="whitespace-nowrap">
219	                {googleLoading ? "..." : "Google"}
220	              </span>
221	            </div>
222	            <div
223	              ref={googleBtnRef}
224	              className="absolute inset-0 overflow-hidden opacity-0"
225	            />
226	          </div>
227	
228	          {/* Apple — disabled */}
229	          <button
230	            type="button"
231	            disabled
232	            className="flex h-12 w-full cursor-not-allowed items-center justify-center gap-2 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-4 py-3 font-medium font-new-sans text-[#44403C] text-sm tracking-[-0.01em] opacity-70 sm:flex-1"
233	          >
234	            <AppleIcon />
235	            <span className="whitespace-nowrap">Apple</span>
236	          </button>
237	
238	          {/* UAE Pass — disabled */}
239	          <button
240	            type="button"
241	            disabled
242	            className="flex h-12 w-full cursor-not-allowed items-center justify-center gap-2 rounded-[4px] border border-[#A8A29E] bg-[#F5F3EF] px-4 py-3 font-medium font-new-sans text-[#44403C] text-sm tracking-[-0.01em] opacity-70 sm:flex-1"
243	          >
244	            <UaePassIcon />
245	            <span className="whitespace-nowrap">UAE Pass</span>
246	          </button>
247	        </div>
248	
249	        {/* Form Section */}
250	        <div className="flex flex-col gap-5">
251	          {/* OR Divider */}
252	          <div className="flex items-center gap-4">
253	            <div className="flex-1 border-[#D6D3D1] border-t" />
254	            <span className="font-bold font-new-sans text-[#A8A29E] text-sm tracking-[-0.01em]">
255	              OR
256	            </span>
257	            <div className="flex-1 border-[#D6D3D1] border-t" />
258	          </div>
259	
260	          <Form {...form}>
261	            <form
262	              onSubmit={form.handleSubmit(onSubmit)}
263	              className="flex flex-col gap-5"
264	            >
265	              <div className="flex flex-col gap-2">
266	                {/* Email */}
267	                <FormField
268	                  control={form.control}
269	                  name="email"
270	                  render={({ field }) => (
271	                    <FormItem>
272	                      <FormLabel className="font-new-sans font-normal text-[#44403C] text-sm leading-[130%]">
273	                        Email
274	                      </FormLabel>
275	                      <FormControl>
276	                        <Input
