  useEffect(() => {
    if (!getIsClient()) return;
    const params = new URLSearchParams(window.location.search);
    setCallbackUrl(params.get("callbackUrl"));
  }, []);

  const handleGoogleCredential = async (response: { credential: string }) => {
    setGoogleLoading(true);
    try {
      const result = await signIn("google-oauth", {
        idToken: response.credential,
        redirect: false,
      });

      if (result?.ok) {
        const params = new URLSearchParams(window.location.search);
        hardPush(params.get("callbackUrl") || APP_ROUTES.APP.MY_DEALS);
      } else {
        toast.error("Google Sign In Failed", {
          description: "Please try again",
        });
        setGoogleLoading(false);
      }
    } catch {
      toast.error("Google Sign In Failed", {
        description: "An unexpected error occurred",
      });
      setGoogleLoading(false);
    }
  };

  const handleAppleSignIn = async () => {
    if (!window.AppleID) return;
    setAppleLoading(true);
    try {
      const response = await window.AppleID.auth.signIn();
      const identityToken = response.authorization.id_token;
      const firstName = response.user?.name?.firstName ?? undefined;
      const lastName = response.user?.name?.lastName ?? undefined;

      const result = await signIn("apple-oauth", {
        identityToken,
        firstName: firstName ?? "",
        lastName: lastName ?? "",
        redirect: false,
      });

      if (result?.ok) {
        const params = new URLSearchParams(window.location.search);
        hardPush(params.get("callbackUrl") || APP_ROUTES.APP.MY_DEALS);
      } else {
        toast.error("Apple Sign In Failed", { description: "Please try again" });
        setAppleLoading(false);
      }
    } catch {
      toast.error("Apple Sign In Failed", { description: "An unexpected error occurred" });
